VALUES
  ('social-worker-moex-03221', 'social-worker', 'social-worker-moex-100-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '非營利組織採用「網絡定位策略」與其外在環境的各部門組織建立關係，關注的重點是「在此網絡關係 中，我們機構有否足以吸引其他機構的資源與能力？是否位居網絡的中心地位？」這是屬於下列何種決 策選擇？', '["介入程度", "移動彈性", "利益分配與核心程度", "競爭優勢"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "8a1eb27a2c6e", "answer_pdf_sha1": "fae618103dc0", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03222', 'social-worker', 'social-worker-moex-100-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '近年來社會服務機構在財務管理策略上，日趨採取對服務案主的收費以增加組織財務資源。若某一社會 服務機構是依據案主付費能力而定的收費方式，這是採取何種收費類型？', '["浮動支出（sliding-scale fees）", "參與支出（participation fees）", "固定支出（flat-rate fees）", "公平分攤支出（fair-share-cost fees）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "8a1eb27a2c6e", "answer_pdf_sha1": "fae618103dc0", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03223', 'social-worker', 'social-worker-moex-100-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '在志工的招募上，基於市場區隔的各團體都有其獨特需要與興趣，所以需發展不同志工的職位與徵募消 息，這是運用何種行銷策略去獲取志工的人力資源？', '["無差異行銷", "差異行銷", "集中行銷", "聯合行銷"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "8a1eb27a2c6e", "answer_pdf_sha1": "fae618103dc0", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03224', 'social-worker', 'social-worker-moex-100-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '組織的領導者重視充權（empowerment）與個別化關懷，讓員工感受到自身任務的重要與個人成長，且能 激發員工為組織利益而非私人利益而努力，這是採取何種領導理論觀點？', '["特質理論（trait theory）", "行為理論（behavior theory）", "轉換型領導理論（transformational leadership theory）", "交易型領導理論（transactional leadership theory）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "8a1eb27a2c6e", "answer_pdf_sha1": "fae618103dc0", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03225', 'social-worker', 'social-worker-moex-100-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '組織的職務設計架構是依據主管想要藉著利用員工的知識、技能及創造潛能，以提高工作效能。此模式 建立在自發性與自制給予最大自由度的假設下，則可以達到能力運用的最佳化，這是屬於下列何種職務 設計模式？', '["傳統模式（the traditional model）", "人力資源模式（the human resources model）", "人群關係模式（the human relations model）", "科層制模式（the bureaucracy model）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "8a1eb27a2c6e", "answer_pdf_sha1": "fae618103dc0", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03226', 'social-worker', 'social-worker-moex-100-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '在甄試員工的面試方法中，面試重點從應試者所具備的成就，轉移到他們是如何達到此成就，以指認應 試者所具備是達成此成就的技術或特質，這是何種面試法？', '["關鍵事件面試法（critical incident interviewing）", "模式化行為描述面試法（patterned behavior description interviewing）", "參與式面試法（participatory interviewing）", "能力為本面試法（competency-based interviewing）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "8a1eb27a2c6e", "answer_pdf_sha1": "fae618103dc0", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03227', 'social-worker', 'social-worker-moex-100-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', 'Kettner 對於方案設計，從問題分析開始到需求評量，建立方案假設，發展出一套層級式之目的與目標， 且認為此層級式的方式具有許多益處，下列對此益處的陳述何者是錯誤的？', '["層級方法協助我們將重點置於問題的解決，而非僅為活動", "層級方法可以將方案活動和成果連結在一起", "層級方法僅能夠作為短程計畫的基礎", "層級方法提供我們一個架構，藉此作為後續監督與評估服務提供過程之用"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "8a1eb27a2c6e", "answer_pdf_sha1": "fae618103dc0", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03228', 'social-worker', 'social-worker-moex-100-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '「與其他地區所提供的服務做比較，您機構所服務的人口百分比是否較高或低？」的陳述，這是屬於下 列何種需求評量的類型？', '["規範性需求（normative need）", "相對性需求（relative need）", "感受性需求（perceived need）", "表達性需求（expressed need）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "8a1eb27a2c6e", "answer_pdf_sha1": "fae618103dc0", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03229', 'social-worker', 'social-worker-moex-100-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '管理者進行方案評估時，採用「內部評估法」具有許多優點，但不包含下列那一項？', '["易於掌握組織結構與方案相關內容", "易於獲得主事者和員工的信任，進而讓他們承認問題和分享秘密", "豐富化服務品質的改善過程，有益於機構外部責信", "易於維持評估工作的客觀性與中立性"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "8a1eb27a2c6e", "answer_pdf_sha1": "fae618103dc0", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03230', 'social-worker', 'social-worker-moex-100-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '社會服務方案進行績效評量，以「送餐到府」的方案為例，下列何者選項是「最終成果」績效評量的指標？', '["一個在接受服務後，能在家維持生活的服務對象", "一份送達時仍是溫熱的餐點", "一個維持充分營養的服務對象", "一份準時送達的餐點"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "8a1eb27a2c6e", "answer_pdf_sha1": "fae618103dc0", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
